import type { Question } from "@/domain/types";

/**
 * Banco de questões — alinhado ao ISTQB CTFL Syllabus v4.0.
 * Quantidade por capítulo suficiente para a distribuição do exame (8/6/4/11/9/2)
 * com variação entre execuções. Edite/adicione questões livremente aqui.
 */
export const QUESTIONS: Question[] = [
  // ---------------- Capítulo 1 ----------------
  { id: "c1-01", chapter: 1, prompt: "Qual das opções NÃO é um objetivo típico do teste?", options: ["Encontrar defeitos e falhas", "Fornecer informação para decisões", "Provar que o software está totalmente livre de defeitos", "Prevenir defeitos ao avaliar requisitos e design"], answerIndex: 2, explanation: "O 1º princípio afirma que <b>o teste mostra a presença de defeitos, mas não prova sua ausência</b>." },
  { id: "c1-02", chapter: 1, prompt: "Uma pessoa comete um engano ao codificar, gerando um problema que, ao ser executado, produz comportamento inesperado. A sequência correta é:", options: ["Falha → defeito → erro", "Erro → defeito → falha", "Defeito → erro → falha", "Erro → falha → defeito"], answerIndex: 1, explanation: "Um <b>erro</b> introduz um <b>defeito</b> no artefato; ao executar o código com defeito, pode ocorrer uma <b>falha</b>." },
  { id: "c1-03", chapter: 1, prompt: 'O princípio "teste exaustivo é impossível" implica que a equipe deve:', options: ["Testar todas as combinações possíveis", "Concentrar esforços usando técnicas, priorização e análise de risco", "Abrir mão de testar", "Automatizar 100% dos cenários"], answerIndex: 1, explanation: "Usa-se <b>análise de risco, priorização e técnicas</b> para focar o esforço onde importa." },
  { id: "c1-04", chapter: 1, prompt: 'O "agrupamento de defeitos" (defect clustering) estabelece que:', options: ["Defeitos se distribuem uniformemente", "Poucos módulos costumam conter a maioria dos defeitos", "Todo defeito resulta em falha", "Defeitos só aparecem no fim"], answerIndex: 1, explanation: "Poucos módulos concentram a maior parte dos defeitos — base do <b>teste baseado em risco</b>." },
  { id: "c1-05", chapter: 1, prompt: 'O "paradoxo do pesticida" indica que:', options: ["Testes automatizados nunca falham", "Repetir os mesmos testes deixa de encontrar novos defeitos", "Quanto mais defeitos, melhor", "Testar cedo elimina o teste tardio"], answerIndex: 1, explanation: "Os mesmos testes param de achar defeitos novos; é preciso <b>revisar e criar novos testes</b>." },
  { id: "c1-06", chapter: 1, prompt: 'A falácia da "ausência de erros" alerta que:', options: ["Corrigir muitos defeitos garante sucesso", "Um sistema pode ter poucos defeitos e ainda não atender às necessidades dos usuários", "Nenhum software tem defeitos", "Corrigir defeitos sempre introduz novos"], answerIndex: 1, explanation: "Mesmo quase sem defeitos, o produto pode ser <b>inutilizável ou não atender às expectativas</b>." },
  { id: "c1-07", chapter: 1, prompt: "Sobre verificação e validação:", options: ["Verificação = produto certo; Validação = corretamente", "Verificação = construir corretamente (conforme especificação); Validação = construir o produto certo (atende necessidades)", "Ambas são o mesmo", "Validação ocorre só em produção"], answerIndex: 1, explanation: "<b>Verificação</b>: construir <i>corretamente</i>. <b>Validação</b>: construir o produto <i>certo</i>." },
  { id: "c1-08", chapter: 1, prompt: "Qual atividade do processo de teste identifica itens de teste e define condições de teste?", options: ["Planejamento", "Análise de teste", "Implementação", "Execução"], answerIndex: 1, explanation: "A <b>análise de teste</b> examina a base de teste e define as <b>condições de teste</b>." },
  { id: "c1-09", chapter: 1, prompt: "Qual afirmação sobre teste e depuração está correta?", options: ["Depuração faz parte do teste dinâmico", "Teste mostra falhas; depuração localiza, analisa e corrige o defeito", "Depurar = executar casos de teste", "São sinônimos"], answerIndex: 1, explanation: "O <b>teste</b> revela falhas; a <b>depuração</b> localiza a causa e corrige o defeito." },
  { id: "c1-10", chapter: 1, prompt: "O viés de confirmação, na psicologia do teste, tende a:", options: ["Ajudar a aceitar informações contrárias", "Dificultar reconhecer os próprios erros e aceitar informações que contrariam crenças", "Eliminar a independência do teste", "Melhorar a comunicação"], answerIndex: 1, explanation: "Leva a resistir a informações que contradizem crenças — daí o valor da <b>independência</b>." },
  { id: "c1-11", chapter: 1, prompt: "A rastreabilidade entre base de teste e testware serve PRINCIPALMENTE para:", options: ["Substituir o gerenciamento de configuração", "Avaliar cobertura, suportar análise de impacto e comunicar progresso aos stakeholders", "Eliminar a necessidade de critérios de saída", "Garantir que todo defeito será encontrado"], answerIndex: 1, explanation: "A <b>rastreabilidade</b> permite avaliar cobertura, facilitar auditorias e comunicar resultados de forma compreensível." },
  { id: "c1-12", chapter: 1, prompt: "Qual é o papel do testador no processo de teste?", options: ["Planejar e monitorar o processo de teste", "Analisar, modelar, implementar e executar testes", "Decidir sobre liberação do produto", "Gerenciar a equipe e recursos"], answerIndex: 1, explanation: "O papel do <b>testador</b> foca nas atividades de análise, modelagem, implementação e execução." },
  { id: "c1-13", chapter: 1, prompt: "A abordagem de 'equipe completa' (whole-team) no teste afirma que:", options: ["Somente testadores são responsáveis pela qualidade", "Qualquer membro com as habilidades necessárias pode testar e todos são responsáveis pela qualidade", "Desenvolvedores nunca devem testar", "A independência total sempre é preferível"], answerIndex: 1, explanation: "Na <b>abordagem de equipe completa</b>, todos compartilham a responsabilidade pela qualidade — vem da Extreme Programming." },
  { id: "c1-14", chapter: 1, prompt: "Qual é uma desvantagem da independência total de testes (testadores externos)?", options: ["Encontram menos tipos de defeitos diferentes", "Podem ficar isolados, gerando problemas de comunicação e relação adversa com o dev", "Nunca questionam as premissas do sistema", "São sempre mais lentos que testadores internos"], answerIndex: 1, explanation: "Testadores externos podem se <b>isolar</b>, causando falta de colaboração, problemas de comunicação e relação adversa." },
  { id: "c1-15", chapter: 1, prompt: "O 'teste antecipado economiza tempo e dinheiro' significa:", options: ["Devemos testar somente no início do projeto", "Defeitos removidos cedo no SDLC não geram artefatos defeituosos posteriores, reduzindo custo da qualidade", "Testes automatizados são sempre mais rápidos", "O planejamento de teste deve acontecer após o desenvolvimento"], answerIndex: 1, explanation: "Defeitos encontrados cedo <b>não se propagam</b> para artefatos derivados — o custo da qualidade cai (Boehm 1981)." },
  { id: "c1-16", chapter: 1, prompt: "O testware produzido na atividade de IMPLEMENTAÇÃO de teste inclui principalmente:", options: ["Plano de teste e registro de riscos", "Condições de teste e casos de teste priorizados", "Procedimentos de teste, scripts, conjuntos de teste e dados de teste", "Relatório de conclusão e lições aprendidas"], answerIndex: 2, explanation: "A <b>implementação</b> produz procedimentos, scripts automatizados, conjuntos de teste, dados e o cronograma de execução." },
  { id: "c1-17", chapter: 1, prompt: "Qual princípio de teste está sendo aplicado quando uma equipe decide focar o esforço nos módulos com maior histórico de defeitos?", options: ["Teste exaustivo é impossível", "Teste antecipado economiza tempo", "Agrupamento de defeitos (defect clustering)", "Os testes se degradam (paradoxo do pesticida)"], answerIndex: 2, explanation: "O <b>agrupamento de defeitos</b> orienta o esforço para módulos que historicamente concentram mais defeitos." },
  { id: "c1-18", chapter: 1, prompt: "Quais habilidades são particularmente relevantes para testadores?", options: ["Apenas habilidades técnicas de programação", "Meticulosidade, atenção a detalhes, comunicação, pensamento analítico e crítico, criatividade", "Somente conhecimento do domínio de negócio", "Apenas experiência com automação de testes"], answerIndex: 1, explanation: "Testadores precisam de <b>múltiplas habilidades genéricas</b>: meticulosidade, comunicação, pensamento crítico, criatividade e conhecimento técnico/de domínio." },
  { id: "c1-19", chapter: 1, prompt: `Qual das seguintes declarações é um objetivo válido para os testes?`, options: [`O teste deve começar o mais tarde possível para o desenvolvimento ter tempo suficiente para criar um bom produto`, `Para validar se o objeto de teste funciona como esperado pelos usuários e outras partes interessadas`, `Para provar que todos os possíveis defeitos são identificados`, `Para provar que qualquer defeito remanescente não causará nenhuma falha`], answerIndex: 1, explanation: `Um objetivo típico do teste é <b>validar se o objeto de teste atende às expectativas dos stakeholders</b>; provar ausência total de defeitos é impossível.` },
  { id: "c1-20", chapter: 1, prompt: `Qual das seguintes declarações descreve corretamente a diferença entre teste e depuração?`, options: [`Os testes identificam a fonte dos defeitos; a depuração analisa os defeitos e propõe atividades de prevenção`, `Os testes dinâmicos mostram falhas causadas por defeitos; a depuração elimina os defeitos, que são a fonte das falhas`, `Os testes não removem as falhas; mas a depuração remove os defeitos que causam as falhas`, `Os testes dinâmicos previnem as causas das falhas; a depuração remove as falhas`], answerIndex: 1, explanation: `O <b>teste dinâmico</b> revela falhas causadas por defeitos; a <b>depuração</b> localiza e remove o defeito que causa a falha.` },
  { id: "c1-21", chapter: 1, prompt: `Qual das declarações abaixo descreve a situação mais comum para uma falha descoberta durante os testes ou na produção?`, options: [`O produto falhou quando o usuário selecionou uma opção em uma caixa de diálogo`, `A versão errada de um arquivo de código-fonte compilado foi incluída na compilação`, `O algoritmo de computação utilizou as variáveis de entrada erradas`, `O desenvolvedor interpretou erroneamente a exigência do algoritmo`], answerIndex: 0, explanation: `A opção descreve uma <b>falha observável</b> (comportamento incorreto do produto durante o uso); as demais descrevem causas/defeitos, não a falha em si.` },
  { id: "c1-22", chapter: 1, prompt: `O Sr. Test tem testado aplicações de software em dispositivos móveis por um período de 5 anos. Durante vários meses, ele não modificou os casos de teste automatizados existentes e não criou novos casos de teste. Isso leva a que cada vez menos defeitos sejam encontrados através da execução dos testes. Que princípio de teste o Sr. Test não observou?`, options: [`Os testes dependem do ambiente`, `Não é possível realizar testes exaustivos`, `A repetição dos mesmos testes não encontrará novos defeitos`, `Defeitos agrupados`], answerIndex: 2, explanation: `Trata-se do <b>paradoxo do pesticida</b>: repetir os mesmos testes deixa de revelar novos defeitos, sendo necessário revisá-los e variá-los.` },
  { id: "c1-23", chapter: 1, prompt: `De que forma os testes podem ser parte da Garantia de Qualidade?`, options: [`Ela garante que os requisitos sejam testados`, `Ela fornece aos desenvolvedores uma lista de bugs`, `Ela garante que o código seja testado`, `Ela assegura que os testes sejam suficientes`], answerIndex: 1, explanation: `O teste contribui para a <b>Garantia da Qualidade</b> ao fornecer informação sobre defeitos (lista de bugs) que orienta a melhoria do processo.` },
  { id: "c1-24", chapter: 1, prompt: `Qual das seguintes atividades faz parte da atividade principal de análise de teste no processo de teste?`, options: [`Identificação de qualquer infraestrutura e ferramentas necessárias`, `Criação de conjuntos de teste a partir de scripts de teste`, `Análise das lições aprendidas para a melhoria do processo`, `Avaliação da base de teste de testabilidade`], answerIndex: 3, explanation: `Avaliar a <b>testabilidade da base de teste</b> é uma tarefa central da atividade de <b>análise de teste</b>.` },
  { id: "c1-25", chapter: 1, prompt: `Combine os seguintes produtos de trabalho de teste (1-4) com a descrição correta (A-D): 1- Conjunto de teste; 2- Caso de teste; 3- Roteiro de teste; 4- Carta de teste. A- Um conjunto de scripts de teste a serem executados em uma execução de teste específica; B- Um conjunto de instruções para a execução de um teste; C- Contém os resultados esperados; D- Documentação das atividades de teste em testes exploratórios baseados em sessões.`, options: [`1A, 2C, 3B, 4D`, `1D, 2B, 3A, 4C`, `1A, 2C, 3D, 4B`, `1D, 2C, 3B, 4A`], answerIndex: 0, explanation: `Conjunto de teste = scripts para uma execução (A); Caso de teste = contém resultados esperados (C); Roteiro de teste = instruções de execução (B); Carta de teste = documentação de sessão exploratória (D).` },
  { id: "c1-26", chapter: 1, prompt: `Qual dos itens a seguir fornece a definição do termo caso de teste?`, options: [`Subconjunto do domínio de valor de uma variável dentro de um componente ou sistema no qual todos os valores devem ser tratados da mesma forma com base na especificação.`, `Um conjunto de condições prévias, insumos, ações, resultados esperados e pós-condições, desenvolvido com base em condições de teste.`, `Produtos de trabalho produzidos durante o processo de teste para uso no planejamento, projeto, execução, avaliação e relatórios sobre testes.`, `Uma fonte para determinar um resultado esperado para comparar com o resultado real do sistema em teste.`], answerIndex: 1, explanation: `Essa é a definição formal de <b>caso de teste</b> no glossário ISTQB.` },
  { id: "c1-27", chapter: 1, prompt: `Qual dos seguintes é um objetivo típico dos testes?`, options: [`Encontrar defeitos e falhas.`, `Para validar os trabalhos do plano do projeto, conforme necessário.`, `Garantir testes completos.`, `Comparar os resultados reais com os resultados esperados.`], answerIndex: 0, explanation: `<b>Encontrar defeitos e falhas</b> é um dos objetivos típicos de teste listados no syllabus, ao lado de avaliar conformidade e fornecer informações para decisões.` },
  { id: "c1-28", chapter: 1, prompt: `Qual dos seguintes é um exemplo de falha em um sistema de controle de velocidade "cruise control" de um carro?`, options: [`O desenvolvedor do sistema esqueceu de renomear variáveis após uma operação de cortar e colar.`, `Código desnecessário que soa um alarme quando a inversão de marcha foi incluída no sistema`, `O sistema deixa de manter uma velocidade definida quando o volume do rádio é aumentado ou diminuído.`, `A especificação do projeto do sistema indica erroneamente as velocidades.`], answerIndex: 2, explanation: `Uma <b>falha</b> é o comportamento real e observável divergente do esperado durante a execução — como o sistema perder a velocidade definida.` },
  { id: "c1-29", chapter: 1, prompt: `Qual dos seguintes aspectos é mais um defeito do que uma causa raiz em um rastreador de fitness?`, options: [`Como o autor dos requisitos não estava familiarizado com o domínio do treinamento físico, ele assumiu erroneamente que os usuários queriam batimentos cardíacos em batidas por hora.`, `O testador da interface do smartphone não tinha sido treinado em testes de transição de estado, então falhou em um defeito grave.`, `Uma variável de configuração incorreta implementada para a função GPS poderia causar problemas de localização durante o horário de verão.`, `Como a projetista nunca havia trabalhado em dispositivos que pudessem ser usados, ela entendeu mal os efeitos da luz solar refletida.`], answerIndex: 2, explanation: `A variável de configuração incorreta é o <b>defeito</b> propriamente dito; as demais opções descrevem <b>causas-raiz</b> (falhas humanas/conhecimento) que levaram a defeitos.` },
  { id: "c1-30", chapter: 1, prompt: `Como resultado da análise de risco, mais testes estão sendo direcionados para aquelas áreas do sistema em teste onde os testes iniciais encontraram mais defeitos do que a média. Qual dos seguintes princípios de teste está sendo aplicado?`, options: [`Cuidado com o paradoxo do pesticida.`, `Os testes são dependentes do contexto.`, `A ausência de erros é uma falácia.`, `Defeitos agrupados.`], answerIndex: 3, explanation: `Direcionar mais testes às áreas que já revelaram mais defeitos é a aplicação do princípio do <b>agrupamento de defeitos</b> (defect clustering).` },
  { id: "c1-31", chapter: 1, prompt: `Dadas as seguintes atividades e tarefas de teste: (a) Projeto do teste (b) Implementação de testes (c) Execução de testes (d) Conclusão do teste; (1) Entrada de pedidos de alteração para relatórios de defeitos em aberto (2) Identificação de dados de teste para apoiar os casos de teste (3) Priorização de procedimentos de teste e criação de dados de teste (4) Analisar as discrepâncias para determinar sua causa. Qual dos seguintes MELHORES combina as atividades com as tarefas?`, options: [`A-2, B-3, C-4, D-1`, `A-2, B-1, C-3, D-4`, `A-3, B-2, C-4, D-1`, `A-3, B-2, C-1, D-4`], answerIndex: 0, explanation: `Projeto identifica dados de teste (2); implementação prioriza procedimentos e cria dados (3); execução analisa discrepâncias (4); conclusão registra pedidos de mudança para defeitos em aberto (1).` },
  { id: "c1-32", chapter: 1, prompt: `Qual dos seguintes MELHORES descreve como o valor é agregado ao manter a rastreabilidade entre a base de teste e os artefatos de teste?`, options: [`Os testes de manutenção podem ser totalmente automatizados com base em mudanças nas exigências iniciais.`, `É possível determinar se um novo caso de teste aumentou a cobertura das exigências.`, `Os gerentes de testes podem identificar quais testadores encontraram os defeitos de maior gravidade.`, `As áreas que podem ser impactadas por efeitos colaterais de uma mudança podem ser alvo de testes de confirmação.`], answerIndex: 1, explanation: `A <b>rastreabilidade</b> entre base de teste e testware permite avaliar o impacto de mudanças na cobertura de requisitos.` },
  { id: "c1-33", chapter: 1, prompt: `Qual das seguintes qualidades é MAIS provável que seja encontrada na mentalidade de um testador e não na de um desenvolvedor?`, options: [`A mentalidade de um testador tende a crescer e amadurecer à medida que o testador ganha experiência.`, `Capacidade de ver o que pode dar errado.`, `Boa comunicação com os membros da equipe.`, `Atenção aos detalhes.`], answerIndex: 1, explanation: `A <b>mentalidade de teste</b> (pensamento crítico, curiosidade, atenção a detalhes) inclui especialmente a habilidade de antecipar o que pode falhar — mais típica de testadores do que desenvolvedores.` },
  { id: "c1-34", chapter: 1, prompt: `Qual dos seguintes explica MELHOR um benefício dos testes independentes?`, options: [`O uso de uma equipe de teste independente permite que a gerência do projeto atribua a responsabilidade pela qualidade da entrega final à equipe de teste.`, `Se uma equipe de teste externa à organização pode ser proporcionada, há benefícios em termos de esta equipe não ser tão facilmente influenciada pelas preocupações de entrega da gerência e por prazos rígidos.`, `Uma equipe de teste independente pode trabalhar totalmente separada dos desenvolvedores e restringir a comunicação a relatórios de defeitos.`, `Quando as especificações contêm ambiguidades e inconsistências, um testador independente pode ser útil para questionar essas suposições e a interpretação feita pelo desenvolvedor.`], answerIndex: 3, explanation: `Um benefício-chave da <b>independência de teste</b> é questionar suposições e interpretações feitas pelos desenvolvedores diante de especificações ambíguas.` },

  // ---------------- Capítulo 2 ----------------
  { id: "c2-01", chapter: 2, prompt: '"Para cada atividade de desenvolvimento há uma atividade de teste correspondente" reforça:', options: ["Que o teste só começa após a codificação", "Que o teste deve começar cedo (shift-left), cada nível com objetivos próprios", "Que basta o teste de sistema", "Que validação substitui verificação"], answerIndex: 1, explanation: "Apoia o <b>teste antecipado (shift-left)</b>: teste acompanha cada fase." },
  {
    id: "c2-02", chapter: 2, prompt: "O teste de componente (unitário) foca em:", options:
      ["Interfaces entre subsistemas", "Componentes/módulos testados isoladamente", "Requisitos de negócio do usuário final", "Todo o sistema integrado"], answerIndex: 1, explanation: "Verifica módulos <b>isoladamente</b>, com mocks/stubs e frameworks."
  },
  { id: "c2-03", chapter: 2, prompt: "O objetivo do teste de integração é avaliar:", options: ["A estrutura interna de um módulo", "As interfaces e interações entre componentes ou sistemas", "A usabilidade da interface", "Apenas requisitos não funcionais"], answerIndex: 1, explanation: "Concentra-se nas <b>interfaces e interações</b> entre componentes ou sistemas." },
  { id: "c2-04", chapter: 2, prompt: "Qual é um tipo reconhecido de teste de aceitação?", options: ["Teste de caixa-branca", "Teste de aceitação do usuário (UAT)", "Cobertura de instrução", "Análise de valor limite"], answerIndex: 1, explanation: "Incluem <b>UAT</b>, aceitação operacional, contratual/regulatória e testes alfa/beta." },
  { id: "c2-05", chapter: 2, prompt: "A diferença entre teste funcional e não funcional é:", options: ["Funcional avalia desempenho; não funcional avalia funções", "Funcional = o que o sistema faz; não funcional = quão bem se comporta", "Ambos avaliam só segurança", "Não funcional é sempre manual"], answerIndex: 1, explanation: "<b>Funcional</b>: o que faz. <b>Não funcional</b>: quão bem (desempenho, usabilidade, segurança)." },
  { id: "c2-06", chapter: 2, prompt: "Teste de confirmação (reteste) e teste de regressão diferem porque:", options: ["São a mesma coisa", "Confirmação verifica se um defeito foi corrigido; regressão verifica se mudanças não causaram novos defeitos", "Regressão é feito antes da correção", "Confirmação só usa dados de produção"], answerIndex: 1, explanation: "<b>Confirmação</b>: reexecuta o caso que falhou. <b>Regressão</b>: garante que mudanças não quebraram o que funcionava." },
  { id: "c2-07", chapter: 2, prompt: "A análise de impacto é usada principalmente para:", options: ["Escrever código", "Identificar consequências de uma mudança e as áreas afetadas que precisam de regressão", "Substituir o teste de aceitação", "Estimar custo de hardware"], answerIndex: 1, explanation: "Avalia mudanças para identificar áreas afetadas — chave no teste de manutenção." },
  { id: "c2-08", chapter: 2, prompt: "O teste alfa e o teste beta diferem porque:", options: ["Alfa é automatizado; beta é manual", "Alfa ocorre no ambiente do desenvolvedor; beta ocorre no ambiente do cliente/usuário", "Beta vem antes de alfa", "São idênticos"], answerIndex: 1, explanation: "<b>Alfa</b>: no local do desenvolvedor. <b>Beta</b>: no ambiente real dos usuários." },
  { id: "c2-09", chapter: 2, prompt: "No TDD (Desenvolvimento Orientado por Testes), a sequência correta é:", options: ["Implementar o código → escrever testes → refatorar", "Escrever testes → implementar o código para satisfazê-los → refatorar", "Refatorar → escrever testes → implementar", "Implementar → refatorar → testar"], answerIndex: 1, explanation: "No <b>TDD</b>: escreve o teste (que falha) → implementa o código mínimo para passar → refatora." },
  { id: "c2-10", chapter: 2, prompt: "Qual é um BENEFÍCIO do DevOps para os testes?", options: ["Elimina a necessidade de testes manuais completamente", "Feedback rápido sobre qualidade do código e se mudanças afetam negativamente o existente", "Reduz a necessidade de automação de testes", "Permite pular o teste de integração"], answerIndex: 1, explanation: "O DevOps promove <b>feedback rápido</b>, CI com shift-left, automação de regressão e visibilidade de características não funcionais." },
  { id: "c2-11", chapter: 2, prompt: "A abordagem shift-left no teste refere-se a:", options: ["Mover o teste para o final do SDLC", "Antecipar o teste no ciclo de vida, realizando-o mais cedo no SDLC", "Testar apenas a interface do usuário", "Substituir testes automatizados por manuais"], answerIndex: 1, explanation: "<b>Shift-left</b>: antecipar o teste — revisar especificações, escrever testes antes do código, usar CI/CD, análise estática prévia." },
  { id: "c2-12", chapter: 2, prompt: "Qual é o propósito das RETROSPECTIVAS no contexto do teste?", options: ["Substituir o relatório de conclusão", "Identificar o que funcionou, o que pode melhorar e como incorporar melhorias futuras", "Apenas revisar o código produzido na iteração", "Definir os critérios de aceite das histórias"], answerIndex: 1, explanation: "<b>Retrospectivas</b>: discutir lições aprendidas e promover melhoria contínua — resultados vão para o relatório de conclusão." },
  { id: "c2-13", chapter: 2, prompt: "Qual característica NÃO faz parte da norma ISO/IEC 25010 para teste não funcional?", options: ["Eficiência de performance", "Usabilidade", "Portabilidade", "Particionamento de equivalência"], answerIndex: 3, explanation: "<b>Particionamento de equivalência</b> é uma técnica de teste — as demais são características de qualidade da ISO 25010." },
  { id: "c2-14", chapter: 2, prompt: "Em modelos de desenvolvimento ágil, os testes de regressão são fortes candidatos à automação porque:", options: ["São sempre mais simples que outros testes", "São executados muitas vezes e crescem a cada iteração", "Exigem poucos dados de teste", "Só precisam ser executados uma vez por release"], answerIndex: 1, explanation: "Conjuntos de regressão são executados repetidamente e crescem — automação é essencial para viabilizá-los em ágil." },
  { id: "c2-15", chapter: 2, prompt: "Quando ocorre o TESTE DE MANUTENÇÃO por 'aposentadoria' de sistema?", options: ["Quando um novo recurso é adicionado", "Quando o sistema chega ao fim de sua vida útil e precisa ser desativado/arquivado", "Quando há migração para nova linguagem de programação", "Quando há hot-fix urgente em produção"], answerIndex: 1, explanation: "<b>Aposentadoria</b>: testa arquivamento de dados, restauração e recuperação quando o sistema é desativado." },
  { id: "c2-16", chapter: 2, prompt: `Como os testes caixa-branca podem ser aplicados durante os testes de aceitação?`, options: [`Para verificar se grandes volumes de dados podem ser transferidos entre sistemas integrados`, `Para verificar se todas as declarações de código e caminhos de decisão de código foram executados`, `Verificar se todos os fluxos do processo de trabalho foram cobertos`, `Para cobrir todas as navegações da página web`], answerIndex: 2, explanation: `Em teste de aceitação, técnicas caixa-branca podem ser usadas para garantir que <b>todos os fluxos de processo de negócio</b> foram cobertos, não a estrutura do código.` },
  { id: "c2-17", chapter: 2, prompt: `Qual das seguintes declarações comparando testes de componentes e testes de sistemas é VERDADEIRA?`, options: [`O teste de componentes verifica a funcionalidade de módulos de software, objetos de programa e classes que são testados separadamente, enquanto o teste de sistema verifica interfaces entre componentes.`, `Os casos de teste para teste de componentes são geralmente derivados das especificações de componentes, especificações de projeto ou modelos de dados, enquanto os casos de teste para teste de sistemas são geralmente derivados das especificações de requisitos ou casos de uso.`, `O teste de componentes concentra-se apenas nas características funcionais, enquanto o teste de sistemas concentra-se nas características funcionais e não funcionais.`, `Os testes de componentes são de responsabilidade dos testadores, enquanto os testes de sistemas são tipicamente de responsabilidade dos usuários.`], answerIndex: 1, explanation: `Teste de componentes deriva de especificações de componente/projeto; teste de sistema deriva de <b>requisitos e casos de uso</b>.` },
  { id: "c2-18", chapter: 2, prompt: `Qual das seguintes opções é VERDADEIRA sobre teste de regressão e teste de confirmação?`, options: [`O objetivo do teste de regressão é verificar se a correção foi implementada com sucesso, enquanto o objetivo do teste de confirmação é confirmar que a correção não tem efeitos colaterais.`, `O objetivo do teste de regressão é detectar efeitos colaterais não intencionais, enquanto o objetivo do teste de confirmação é verificar se o sistema ainda está funcionando em um novo ambiente.`, `O objetivo do teste de regressão é detectar efeitos colaterais não intencionais, enquanto o objetivo do teste de confirmação é verificar se o defeito original foi corrigido.`, `O objetivo do teste de regressão é verificar se a nova funcionalidade está funcionando, enquanto o objetivo do teste de confirmação é verificar se o defeito original foi corrigido.`], answerIndex: 2, explanation: `<b>Regressão</b>: detecta efeitos colaterais indesejados de mudanças. <b>Confirmação</b>: verifica se o defeito original foi corrigido.` },
  { id: "c2-19", chapter: 2, prompt: `Qual das seguintes definições é a MELHOR definição de um modelo de desenvolvimento incremental?`, options: [`Definição de requisitos, projeto de software e testes são feitos em fases em que cada parte do sistema é adicionada.`, `Uma fase no processo de desenvolvimento deve começar quando a fase anterior estiver concluída.`, `Os testes são vistos como uma fase separada que ocorre após a conclusão do desenvolvimento.`, `Os testes são adicionados ao desenvolvimento como um incremento.`], answerIndex: 0, explanation: `No <b>desenvolvimento incremental</b>, requisitos, projeto e testes ocorrem repetidamente à medida que partes do sistema são adicionadas (incrementos).` },
  { id: "c2-20", chapter: 2, prompt: `Qual dos seguintes itens NÃO deve ser um gatilho para testes de manutenção?`, options: [`Decisão de testar a possibilidade de manutenção do software`, `Decisão de testar o sistema após a migração para uma nova plataforma operacional`, `Decisão de testar se os dados arquivados são possíveis de serem recuperados`, `Decisão de testar após "hot fixes"`], answerIndex: 0, explanation: `Testar a <b>manutenibilidade</b> do software é uma característica de qualidade avaliada, não um gatilho (trigger) para iniciar testes de manutenção como migrações, hot-fixes ou aposentadoria.` },
  { id: "c2-21", chapter: 2, prompt: `Dadas as seguintes declarações sobre as relações entre as atividades de desenvolvimento de software e as atividades de teste no ciclo de vida de desenvolvimento de software: (1) Cada atividade de desenvolvimento deve ter uma atividade de teste correspondente. (2) A revisão deve começar assim que as versões finais dos documentos estiverem disponíveis. (3) O projeto e a implementação de testes devem começar durante a atividade de desenvolvimento correspondente. (4) As atividades de teste devem começar nos estágios iniciais do ciclo de vida de desenvolvimento de software. Quais dos seguintes CORRETAMENTE mostram quais são verdadeiros e quais são falsos?`, options: [`Verdadeiro - 1, 2; Falso - 3, 4`, `Verdadeiro - 2, 3; Falso - 1, 4`, `Verdadeiro - 1, 2, 4; Falso - 3`, `Verdadeiro - 1, 4; Falso - 2, 3`], answerIndex: 3, explanation: `É verdade que cada atividade de dev tem uma atividade de teste correspondente (1) e que o teste deve começar cedo no SDLC (4). É falso que a revisão só comece com documentos finais (2) — deve ocorrer em rascunhos; e falso que projeto/implementação de testes ocorra durante a atividade de dev correspondente (3) — no shift-left isso é antecipado.` },
  { id: "c2-22", chapter: 2, prompt: `Dado que os testes que estão sendo realizados têm os seguintes atributos: - Com base nas especificações da interface - Focado em encontrar falhas na comunicação - A abordagem de teste utiliza tanto tipos de teste funcionais quanto estruturais. Qual dos seguintes níveis de teste é o MAIS provável de ser realizado?`, options: [`Teste de integração`, `Teste de aceitação`, `Teste do sistema`, `Teste de componentes`], answerIndex: 0, explanation: `Testes baseados em interfaces, focados em falhas de comunicação entre componentes, usando tipos funcionais e estruturais, caracterizam o <b>teste de integração</b>.` },
  { id: "c2-23", chapter: 2, prompt: `Qual das seguintes declarações sobre tipos e níveis de teste é CORRETA?`, options: [`Os testes funcionais e não funcionais podem ser realizados nos níveis de teste do sistema e de aceitação, enquanto o teste caixa-branca é restrito aos testes de componentes e de integração.`, `Os testes funcionais podem ser realizados em qualquer nível de teste, enquanto o teste caixa-branca é restrito ao teste de componentes.`, `É possível realizar testes funcionais, não-funcionais e caixa-branca em qualquer nível de teste.`, `Os testes funcionais e não funcionais podem ser realizados em qualquer nível de teste, enquanto os testes caixa-branca são restritos aos testes de componentes e integração.`], answerIndex: 2, explanation: `Tipos de teste (funcional, não funcional, caixa-branca, relacionado a mudanças) podem ser aplicados em <b>qualquer nível de teste</b> — não há restrição de nível.` },
  { id: "c2-24", chapter: 2, prompt: `Qual das seguintes declarações BEST compara os propósitos de teste de confirmação e teste de regressão?`, options: [`O objetivo do teste de regressão é garantir que todos os testes executados anteriormente ainda funcionem corretamente, enquanto o objetivo do teste de confirmação é garantir que reparos não afetaram adversamente outras partes.`, `O objetivo do teste de confirmação é verificar se um defeito previamente encontrado foi corrigido, enquanto o objetivo do teste de regressão é garantir que nenhuma outra parte do sistema foi afetada adversamente pela correção.`, `O objetivo dos testes de regressão é assegurar que mudanças em uma parte do sistema não causem falha em outra parte, enquanto o objetivo dos testes de confirmação é verificar se todos os testes anteriores ainda fornecem os mesmos resultados.`, `O objetivo dos testes de confirmação é confirmar que as mudanças foram feitas com sucesso, enquanto o objetivo dos testes de regressão é executar testes que anteriormente não funcionavam.`], answerIndex: 1, explanation: `Mesma distinção: <b>confirmação</b> = defeito corrigido; <b>regressão</b> = nenhum efeito colateral em outras partes.` },
  { id: "c2-25", chapter: 2, prompt: `Qual das seguintes declarações descreve CORRETAMENTE um papel da análise de impacto nos testes de manutenção?`, options: [`A análise de impacto é utilizada quando se decide se vale a pena uma correção para um sistema mantido.`, `A análise de impacto é utilizada para identificar como os dados devem ser migrados para o sistema mantido.`, `A análise de impacto é utilizada para decidir quais correções quentes são de maior valor para o usuário.`, `A análise de impacto é utilizada para determinar a eficácia de novos casos de teste de manutenção.`], answerIndex: 0, explanation: `A <b>análise de impacto</b> avalia as consequências e o custo/benefício de uma mudança em um sistema já em manutenção.` },

  // ---------------- Capítulo 3 ----------------
  { id: "c3-01", chapter: 3, prompt: "O teste estático se caracteriza por:", options: ["Executar o código para observar falhas", "Avaliar artefatos sem executar o código (revisões e análise estática)", "Ser feito só em produção", "Exigir dados de teste dinâmicos"], answerIndex: 1, explanation: "Examina artefatos <b>sem executar</b> — revisões (manual) e análise estática (ferramenta)." },
  { id: "c3-02", chapter: 3, prompt: "Qual é um benefício-chave do teste estático?", options: ["Só encontra falhas de tempo de execução", "Detecta defeitos cedo (mais baratos) e acha problemas que o teste dinâmico dificilmente encontraria", "Elimina o teste dinâmico", "Requer código executável pronto"], answerIndex: 1, explanation: "Encontra defeitos <b>cedo</b> e detecta requisitos ambíguos, código morto/inalcançável." },
  { id: "c3-03", chapter: 3, prompt: "Do menos ao mais formal, a ordem dos tipos de revisão é:", options: ["Inspeção → técnica → walkthrough → informal", "Informal → walkthrough → revisão técnica → inspeção", "Walkthrough → informal → inspeção → técnica", "Técnica → inspeção → informal → walkthrough"], answerIndex: 1, explanation: "<b>Informal → walkthrough → revisão técnica → inspeção</b> (a mais formal)." },
  { id: "c3-04", chapter: 3, prompt: "Numa inspeção formal, quem lidera a reunião?", options: ["O autor", "O moderador (facilitador)", "O gerente de projeto", "O cliente"], answerIndex: 1, explanation: "O <b>moderador/facilitador</b> conduz a reunião — nunca o autor." },
  { id: "c3-05", chapter: 3, prompt: "Qual é a função do escriba (scribe) numa revisão?", options: ["Corrigir os defeitos", "Registrar defeitos, decisões e ações da reunião", "Aprovar o documento", "Liderar a reunião"], answerIndex: 1, explanation: "O <b>escriba</b> registra as anomalias, decisões e ações." },
  { id: "c3-06", chapter: 3, prompt: "O walkthrough é tipicamente liderado por:", options: ["O moderador independente", "O autor do produto de trabalho", "Um auditor externo", "O escriba"], answerIndex: 1, explanation: "No <b>walkthrough</b>, geralmente o <b>autor</b> conduz a sessão." },
  { id: "c3-07", chapter: 3, prompt: "Um fator de sucesso para revisões é:", options: ["Avaliar o desempenho do autor", "Tratar defeitos de forma objetiva, sem culpar o autor", "Revisar sem objetivos", "Incluir só o autor"], answerIndex: 1, explanation: "Defeitos são bem-vindos e expressos <b>objetivamente</b>, sem julgar a pessoa." },
  { id: "c3-08", chapter: 3, prompt: "Qual tipo de defeito é mais facilmente encontrado por teste ESTÁTICO do que por dinâmico?", options: ["Erros de runtime durante execução", "Requisitos ambíguos, código inacessível e desvios de padrão", "Falhas de desempenho sob carga", "Erros de integração entre sistemas externos"], answerIndex: 1, explanation: "Estático detecta <b>requisitos ambíguos, código inacessível, desvios de padrão</b> — coisas difíceis de achar executando." },
  { id: "c3-09", chapter: 3, prompt: "Na inspeção formal, o autor NÃO pode assumir qual papel?", options: ["Revisor", "Líder da revisão ou relator", "Participante da reunião", "Responsável pela correção"], answerIndex: 1, explanation: "Na <b>inspeção</b>, o autor não pode ser <b>líder da revisão nem relator</b> — garante objetividade." },
  { id: "c3-10", chapter: 3, prompt: "O feedback antecipado e frequente dos stakeholders durante o SDLC tem como principal benefício:", options: ["Eliminar a necessidade de testes dinâmicos", "Evitar mal-entendidos de requisitos, retrabalho dispendioso e prazos perdidos", "Substituir as revisões formais", "Reduzir o número de testadores necessários"], answerIndex: 1, explanation: "Feedback frequente evita <b>mal-entendidos</b>, retrabalho caro e garante que mudanças sejam implementadas cedo." },
  { id: "c3-11", chapter: 3, prompt: "Qual é a diferença principal entre revisão informal e inspeção?", options: ["Informais não detectam defeitos", "Informal não tem processo definido nem resultado documentado; inspeção segue processo completo com métricas", "Inspecções são lideradas pelo autor", "Informais são sempre mais eficazes"], answerIndex: 1, explanation: "<b>Informal</b>: sem processo definido, sem resultado formal. <b>Inspeção</b>: processo completo, métricas coletadas, mais formal." },
  { id: "c3-12", chapter: 3, prompt: "Qual produto de trabalho NÃO é adequado para teste estático?", options: ["Especificação de requisitos", "Código-fonte", "Código executável de terceiros (por restrições legais)", "Plano de teste"], answerIndex: 2, explanation: "Código executável de terceiros com restrições legais é <b>difícil de interpretar</b> e não pode ser analisado." },
  { id: "c3-13", chapter: 3, prompt: `Quais das seguintes opções são papéis em uma revisão formal?`, options: [`Desenvolvedor, Moderador, Líder de revisão, Revisor, Testador.`, `Autor, Moderador, Gerente, Revisor, Desenvolvedor.`, `Autor, Gerente, Líder de revisão, Revisor, Designer.`, `Autor, Moderador, Líder de revisão, Revisor, Redator.`], answerIndex: 3, explanation: `Os papéis típicos de uma <b>revisão formal</b> são autor, moderador, líder de revisão, revisor e redator (escriba).` },
  { id: "c3-14", chapter: 3, prompt: `Quais atividades são realizadas no âmbito do planejamento de uma revisão formal?`, options: [`Coleta de métricas para a avaliação da eficácia da revisão.`, `Responder a quaisquer perguntas que os participantes possam ter.`, `Definição e verificação do cumprimento dos critérios de entrada para a revisão`, `Avaliação dos resultados da revisão em relação aos critérios de saída`], answerIndex: 2, explanation: `No <b>planejamento</b> da revisão, definem-se e verificam-se os critérios de entrada, escopo, papéis e cronograma.` },
  { id: "c3-15", chapter: 3, prompt: `Qual dos tipos de revisão abaixo é a MELHOR opção para escolher quando a revisão deve seguir um processo formal baseado em regras e listas de verificação?`, options: [`Revisão Informal`, `Revisão Técnica`, `Inspeção`, `Passagem`], answerIndex: 2, explanation: `A <b>inspeção</b> é o tipo de revisão mais formal, guiada por regras e listas de verificação definidas.` },
  { id: "c3-16", chapter: 3, prompt: `Quais das seguintes afirmações sobre testes estáticos são as mais verdadeiras?`, options: [`Os testes estáticos são uma forma barata de detectar e remover defeitos.`, `Os testes estáticos tornam os testes Dinâmicos menos desafiadores`, `Os testes estáticos permitem encontrar problemas de tempo de execução no início do ciclo de vida`, `Ao testar um sistema crítico de segurança, os testes estáticos têm menos valor porque os testes dinâmicos encontram melhor os defeitos.`], answerIndex: 0, explanation: `Como não requer execução do código, o <b>teste estático</b> encontra e remove defeitos de forma mais barata e cedo no ciclo de vida.` },
  { id: "c3-17", chapter: 3, prompt: `Você foi convidado para uma revisão baseada em checklist de uma descrição do processo de criação de documentos internos. A checklist inclui: I. A pessoa que executa a atividade é claramente identificada? II. Critérios de entrada claramente definidos? III. Critérios de saída claramente definidos? IV. Papéis de apoio claramente definidos? No trecho revisado: "Após verificar a documentação do cliente, o arquiteto do software cria a especificação do sistema. Uma vez concluída, ele convida os testadores e verificadores para a revisão. Uma lista de verificação descreve o escopo. Cada revisor cria comentários — se necessário — e conclui com um comentário oficial." Qual das seguintes declarações sobre sua revisão é correta?`, options: [`O ponto II foi violado porque não está claro qual condição deve ser preenchida para convidar para a revisão.`, `Você percebe que o validador também deveria ser convidado, mas como não faz parte da checklist, não cria um comentário.`, `O ponto III foi violado, pois não está claro o que marca a revisão como concluída.`, `O ponto I foi violado porque não está claro quem está fornecendo a lista de verificação para o convite para a revisão.`], answerIndex: 3, explanation: `O ponto I exige que a pessoa responsável por cada atividade esteja claramente identificada; o texto não deixa claro quem fornece a checklist para o convite, violando esse critério.` },
  { id: "c3-18", chapter: 3, prompt: `Qual das seguintes afirmações reflete CORRETAMENTE o valor dos testes estáticos?`, options: [`Ao introduzir revisões, descobrimos que tanto a qualidade das especificações quanto o tempo necessário para o desenvolvimento e os testes aumentaram.`, `Usando testes estáticos significa que temos melhor controle e gerenciamento de defeitos mais barato devido à facilidade de detecção de defeitos mais tarde no ciclo de vida.`, `Agora que exigimos o uso de análise estática, as exigências não atendidas diminuíram e a comunicação entre testadores e desenvolvedores melhorou.`, `Desde que começamos a usar análise estática, encontramos defeitos de codificação que podem não ter sido encontrados realizando apenas testes dinâmicos.`], answerIndex: 3, explanation: `Um valor concreto do teste estático é revelar defeitos de codificação que o teste dinâmico sozinho poderia não encontrar.` },
  { id: "c3-19", chapter: 3, prompt: `Qual das seguintes declarações sobre o uso de listas de verificação em uma revisão formal é CORRETA?`, options: [`Como parte do planejamento da revisão, os revisores criam as listas de verificação necessárias para a revisão.`, `Como parte da comunicação da questão, os revisores preenchem as listas de verificação previstas para a revisão.`, `Como parte da reunião de revisão, os revisores criam relatórios de defeitos com base nas listas de verificação previstas para a revisão.`, `Como parte do início da revisão, os revisores recebem as listas de verificação necessárias para a revisão.`], answerIndex: 3, explanation: `As listas de verificação são distribuídas aos revisores na atividade de <b>início da revisão</b> (kick-off), não criadas por eles.` },
  { id: "c3-20", chapter: 3, prompt: `Qual das seguintes funções e responsabilidades se encaixa CORRETAMENTE em uma revisão formal?`, options: [`Gerente - Decide sobre a execução das revisões`, `Líder de revisão - Assegura o funcionamento eficaz das reuniões de revisão`, `Escriba - Corrige defeitos no produto de trabalho em revisão`, `Moderador - Monitora a relação custo-benefício contínua`], answerIndex: 0, explanation: `O <b>gerente</b> decide sobre a realização das revisões, aloca tempo e recursos no cronograma do projeto.` },
  { id: "c3-21", chapter: 3, prompt: `As revisões utilizadas em sua organização têm os seguintes atributos: há um papel de escriba; o objetivo é detectar defeitos potenciais; a reunião é liderada pelo autor; os revisores encontram defeitos potenciais por revisão individual; é produzido um relatório de revisão. Qual dos seguintes tipos de revisão é o MAIS provável que seja utilizado?`, options: [`Revisão Informal`, `Caminhada`, `Revisão Técnica`, `Inspeção`], answerIndex: 2, explanation: `Papel de escriba, foco em detectar defeitos, reunião liderada pelo autor e produção de relatório de revisão são características típicas da <b>revisão técnica</b>.` },
  { id: "c3-22", chapter: 3, prompt: `Você foi convidado a participar de uma revisão baseada em checklist da especificação de requisitos de um sistema de biblioteca, com a tarefa de identificar inconsistências entre requisitos individuais. Entre os requisitos: (6) obter respostas do sistema em 5 segundos (bibliotecários); (9) mutuário multado por não devolver livro em 3 semanas; (10) mutuário obter respostas do sistema em 3 segundos; (11) mutuário pode emprestar um livro sem custo por até 4 semanas; (15) o sistema deve responder a todos os usuários em 3 segundos. Qual dos seguintes CORRETAMENTE identifica inconsistências entre pares de requisitos?`, options: [`6-10, 6-15, 7-12`, `6-15, 9-11`, `6-10, 6-15, 9-11`, `6-15, 7-12`], answerIndex: 1, explanation: `O requisito 6 (5s para bibliotecários) conflita com o requisito geral 15 (3s para todos os usuários). O requisito 9 (multa após 3 semanas) conflita com o requisito 11 (empréstimo grátis por até 4 semanas).` },

  // ---------------- Capítulo 4 ----------------
  { id: "c4-01", chapter: 4, prompt: "Um campo aceita idades de 18 a 65. No particionamento de equivalência, quantas partições existem?", options: ["1", "2", "3", "4"], answerIndex: 2, explanation: "<b>3 partições</b>: inválida (<18), válida (18–65) e inválida (>65)." },
  { id: "c4-02", chapter: 4, prompt: "Para o intervalo 18–65, quais valores a análise de valor limite (2 valores) sugere?", options: ["Só 18 e 65", "17, 18, 65 e 66", "0 e 100", "18, 40 e 65"], answerIndex: 1, explanation: "Limite e vizinho: <b>17, 18</b> e <b>65, 66</b>." },
  { id: "c4-03", chapter: 4, prompt: "A tabela de decisão é especialmente útil quando:", options: ["Há uma entrada e uma saída", "Combinações de condições levam a diferentes ações/regras", "Deseja-se medir cobertura de código", "Não há regras de negócio"], answerIndex: 1, explanation: "Modela <b>combinações de condições</b> e ações — ideal para lógica de negócio." },
  { id: "c4-04", chapter: 4, prompt: "O teste de transição de estado modela o sistema em termos de:", options: ["Instruções e desvios", "Estados, eventos, transições e ações", "Partições de entrada apenas", "Riscos de projeto"], answerIndex: 1, explanation: "Representa <b>estados, eventos, transições e ações</b>." },
  { id: "c4-05", chapter: 4, prompt: "A cobertura de instruções (statement) mede:", options: ["% de decisões exercitadas", "% de instruções executáveis exercitadas", "Defeitos por módulo", "Cobertura de requisitos"], answerIndex: 1, explanation: "% de <b>comandos executáveis</b> efetivamente executados." },
  { id: "c4-06", chapter: 4, prompt: "Sobre cobertura de decisão e de instrução:", options: ["100% de instrução garante 100% de decisão", "100% de decisão garante 100% de instrução, mas não o inverso", "São sempre equivalentes", "Nenhuma implica a outra"], answerIndex: 1, explanation: "<b>Decisão é mais forte</b>: 100% de decisão ⇒ 100% de instrução (não o contrário)." },
  { id: "c4-07", chapter: 4, prompt: "Qual técnica é baseada em experiência?", options: ["Particionamento de equivalência", "Suposição de erro (error guessing)", "Tabela de decisão", "Análise de valor limite"], answerIndex: 1, explanation: "<b>Suposição de erro</b>, exploratório e baseado em checklist são baseados em experiência." },
  { id: "c4-08", chapter: 4, prompt: "No ATDD, os casos de teste são:", options: ["Escritos só após a entrega", "Derivados colaborativamente dos critérios de aceitação, antes de codificar", "Gerados pela ferramenta", "Ignorados"], answerIndex: 1, explanation: "Equipe define critérios e testes de aceitação <b>colaborativamente antes</b> do dev." },
  { id: "c4-09", chapter: 4, prompt: "O teste exploratório caracteriza-se por:", options: ["Roteiros detalhados prévios", "Projeto e execução simultâneos, com aprendizado sobre o sistema", "Ausência de objetivos", "Ser sempre automatizado"], answerIndex: 1, explanation: "Projeto, execução e aprendizado <b>simultâneos</b>, guiados por test charters." },
  { id: "c4-10", chapter: 4, prompt: "O particionamento de equivalência baseia-se na ideia de que:", options: ["Todo valor deve ser testado", "Valores de uma mesma partição são processados da mesma forma, bastando 1 representante", "Só valores inválidos importam", "Limites nunca falham"], answerIndex: 1, explanation: "Um <b>representante</b> por partição cobre a partição inteira (válidas e inválidas)." },
  { id: "c4-11", chapter: 4, prompt: "A técnica baseada em checklist consiste em:", options: ["Gerar entradas aleatórias", "Verificar itens de uma lista pré-definida de condições a checar", "Medir cobertura de ramos", "Escrever a tabela de decisão"], answerIndex: 1, explanation: "Usa uma <b>lista de verificação</b> derivada de experiência, padrões ou riscos." },
  { id: "c4-12", chapter: 4, prompt: "Qual é a diferença entre caixa-preta e caixa-branca?", options: ["Caixa-preta usa o código; caixa-branca usa a especificação", "Caixa-preta baseia-se no comportamento/especificação; caixa-branca, na estrutura interna/código", "São sinônimos", "Caixa-branca é sempre manual"], answerIndex: 1, explanation: "<b>Caixa-preta</b>: especificação. <b>Caixa-branca</b>: estrutura/código." },
  { id: "c4-13", chapter: 4, prompt: "Um programa tem 10 instruções; os testes executam 7. A cobertura de instruções é:", options: ["100%", "70%", "7%", "Não é possível calcular"], answerIndex: 1, explanation: "7 de 10 = <b>70%</b> de cobertura de instruções." },
  { id: "c4-14", chapter: 4, prompt: "Para a BVA de 3 valores aplicada ao intervalo 18–65, quais são os valores de teste corretos?", options: ["17, 18, 65, 66", "17, 18, 19, 64, 65, 66", "18, 65", "16, 17, 18, 65, 66, 67"], answerIndex: 1, explanation: "<b>BVA 3 valores</b>: limite + dois vizinhos → 17,18,19 (limite inferior) e 64,65,66 (limite superior)." },
  { id: "c4-15", chapter: 4, prompt: "A diferença entre BVA de 2 valores e BVA de 3 valores é:", options: ["BVA 2 valores é mais rigorosa", "BVA 3 valores é mais rigorosa e pode detectar defeitos que BVA 2 valores perderia", "São equivalentes em rigor", "BVA 3 valores só se aplica a partições inválidas"], answerIndex: 1, explanation: "<b>BVA 3 valores</b> inclui os dois vizinhos de cada limite e detecta erros como 'if (x=10)' em vez de 'if (x≤10)'." },
  { id: "c4-16", chapter: 4, prompt: "Na tabela de decisão, o símbolo '-' (traço) em uma condição significa:", options: ["A condição é sempre falsa", "O valor da condição é irrelevante para o resultado daquela regra", "A condição é inviável", "A ação não ocorre"], answerIndex: 1, explanation: "'-' significa que o valor da condição é <b>irrelevante</b> para o resultado — ela não afeta a ação naquela coluna." },
  { id: "c4-17", chapter: 4, prompt: "A cobertura de 'todos os estados' na transição de estado é considerada:", options: ["A mais rigorosa das coberturas", "A mais fraca — pode ser obtida sem executar todas as transições", "Equivalente à cobertura de transições válidas", "Adequada para sistemas de missão crítica"], answerIndex: 1, explanation: "<b>Cobertura de todos os estados</b> é a mais fraca — não garante que todas as transições foram exercitadas." },
  { id: "c4-18", chapter: 4, prompt: "A sigla INVEST para histórias de usuário significa:", options: ["Independente, Negociável, Valioso, Estimável, Small, Testável", "Integrado, Numérico, Válido, Explícito, Simples, Técnico", "Incremental, Necessário, Verificável, Eficiente, Seguro, Tangível", "Identificável, Novo, Versátil, Escalável, Simples, Testado"], answerIndex: 0, explanation: "<b>INVEST</b>: Independente, Negociável, Valiosa, Estimável, Small (pequena), Testável — critérios de qualidade para histórias." },
  { id: "c4-19", chapter: 4, prompt: "Um ponto fraco das técnicas caixa-branca é:", options: ["Não considera o código-fonte", "Se o software não implementou um requisito, a ausência pode não ser detectada", "Só pode ser usada em testes de sistema", "Não fornece medição objetiva de cobertura"], answerIndex: 1, explanation: "Caixa-branca testa o que está implementado — <b>requisitos não implementados</b> podem passar despercebidos." },
  { id: "c4-20", chapter: 4, prompt: "No ATDD, após os casos de teste positivos serem criados, a equipe deve:", options: ["Encerrar a criação de casos de teste", "Criar testes negativos e depois cobrir características não funcionais", "Iniciar imediatamente a implementação", "Aguardar o cliente validar todos os casos positivos primeiro"], answerIndex: 1, explanation: "Ordem no ATDD: 1º casos <b>positivos</b> → 2º casos <b>negativos</b> → 3º características <b>não funcionais</b>." },
  { id: "c4-21", chapter: 4, prompt: "Os 'ataques a falhas' (fault attacks) são uma abordagem metódica de qual técnica?", options: ["Particionamento de equivalência", "Suposição de erro (error guessing)", "Análise de valor limite", "Teste exploratório"], answerIndex: 1, explanation: "<b>Ataques a falhas</b> são a implementação sistemática da suposição de erro — lista de prováveis erros/defeitos/falhas." },
  { id: "c4-22", chapter: 4, prompt: `Qual das seguintes respostas descreve uma condição de teste?`, options: [`Uma característica distinta de um componente ou sistema`, `Um aspecto testável de um componente ou sistema identificado como base para os testes`, `O grau em que um produto de software fornece funções que atendem às necessidades declaradas e implícitas quando o software é utilizado sob condições específicas`, `Casos de teste projetados para executar combinações de condições e ações resultantes delas`], answerIndex: 1, explanation: `Essa é a definição de <b>condição de teste</b> segundo o glossário ISTQB.` },
  { id: "c4-23", chapter: 4, prompt: `Qual das seguintes opções é classificada como uma técnica de teste caixa-preta?`, options: [`Uma técnica baseada na análise da arquitetura`, `Uma técnica que verifica se o objeto de teste está funcionando de acordo com o projeto detalhado`, `Uma técnica baseada no conhecimento de falhas do passado, ou conhecimento geral de falhas`, `Uma técnica baseada em requisitos formais`], answerIndex: 3, explanation: `Técnicas <b>caixa-preta</b> derivam testes a partir de especificações/requisitos formais, sem considerar a estrutura interna do código.` },
  { id: "c4-24", chapter: 4, prompt: `A seguinte declaração se refere à cobertura de decisões: "Quando o código contém apenas uma única declaração 'se' e sem loops ou declarações CASE, e sua execução não está aninhada dentro do teste, qualquer caso de teste único que executarmos resultará em 50% de cobertura de decisão". Qual das seguintes afirmações é correta?`, options: [`A declaração é verdadeira. Qualquer caso de teste único fornece 100% de cobertura de decisão e, portanto, 50% de cobertura de decisão.`, `A afirmação é verdadeira. Qualquer caso isolado de teste faria com que o resultado da declaração "se" fosse verdadeiro ou falso.`, `A afirmação é falsa. Um único caso de teste só pode garantir uma cobertura de decisão de 25% neste caso.`, `A afirmação é falsa. A declaração é muito ampla. Ela pode estar correta ou não, dependendo do software testado.`], answerIndex: 1, explanation: `Com um único 'se' sem aninhamento, cada caso de teste exercita um dos dois resultados possíveis (verdadeiro ou falso), garantindo 50% de cobertura de decisão por execução.` },
  { id: "c4-25", chapter: 4, prompt: `Qual das seguintes é a descrição da cobertura das declarações?`, options: [`É uma métrica, que é a porcentagem de casos de teste que foram executados`, `É uma métrica, que é a porcentagem de declarações no código fonte que foram executadas`, `É uma métrica, que é o número de declarações no código fonte que foram executadas por casos de teste que são aprovados`, `É uma métrica, que dá uma confirmação verdadeira/falsa se todas as declarações são cobertas ou não`], answerIndex: 1, explanation: `<b>Cobertura de instruções (statements)</b> mede o percentual de instruções executáveis do código-fonte exercitadas pelos testes.` },
  { id: "c4-26", chapter: 4, prompt: `Qual declaração sobre a relação entre a cobertura de declarações e a cobertura de decisões é verdadeira?`, options: [`100% de cobertura de decisão também garante 100% de cobertura de declaração`, `100% de cobertura de declaração também garante 100% de cobertura de decisão`, `50% de cobertura de decisão também garante 50% de cobertura de declaração`, `A cobertura de decisão nunca pode chegar a 100%.`], answerIndex: 0, explanation: `A cobertura de decisão é <b>mais forte</b>: alcançar 100% dela implica automaticamente 100% de cobertura de instrução, mas o inverso não é garantido.` },
  { id: "c4-27", chapter: 4, prompt: `Para qual das seguintes situações é adequado o teste exploratório?`, options: [`Quando a pressão do tempo requer a aceleração da execução de testes já especificados`, `Quando o sistema é desenvolvido de forma incremental, e não há carta de teste disponível`, `Quando houver testadores disponíveis que tenham conhecimento suficiente de aplicações e tecnologias similares`, `Quando já existe um conhecimento avançado do sistema, e é necessário fornecer provas de que ele deve ser testado intensivamente`], answerIndex: 2, explanation: `O <b>teste exploratório</b> é mais eficaz quando conduzido por testadores experientes, com bom conhecimento do domínio e da tecnologia.` },
  { id: "c4-28", chapter: 4, prompt: `O bônus de um funcionário deve ser calculado, não pode ser negativo, mas pode ser calculado até zero. O bônus é baseado na duração do emprego: menor ou igual a 2 anos; mais de 2 anos mas menos de 5 anos; 5 a 10 anos inclusive; mais de 10 anos. Qual é o número mínimo de casos de teste necessário para cobrir todas as partições de equivalência válidas para o cálculo do bônus?`, options: [`3`, `5`, `2`, `4`], answerIndex: 3, explanation: `As quatro partições válidas (≤2 anos, >2 e <5, 5–10, >10 anos) exigem <b>4 casos de teste</b>, um representante por partição.` },
  { id: "c4-29", chapter: 4, prompt: `Um sistema de controle de velocidade e relatórios: se dirigir 50 km/h ou menos, nada acontece; mais rápido que 50 mas não mais que 55, é avisado; mais rápido que 55 mas não mais que 60, é multado; mais de 60, a carteira é suspensa. A velocidade está disponível como valor inteiro. Qual seria o conjunto mais provável de valores (km/h) identificado pela aplicação da análise de valores limite, onde apenas os valores nos limites das classes de equivalência são selecionados?`, options: [`0, 49, 50, 54, 59, 60`, `50, 55, 60`, `49, 50, 54, 55, 60, 62`, `50, 51, 55, 56, 60, 61`], answerIndex: 3, explanation: `Como a velocidade é um inteiro, os limites de cada classe de equivalência exigem o próprio valor-limite e seu vizinho imediato: 50/51, 55/56 e 60/61.` },
  { id: "c4-30", chapter: 4, prompt: `Funcionários recebem bônus se trabalharem mais de um ano e atingirem uma meta acordada. Tabela de decisão: T1(Emprego>1ano=SIM, Objetivo acordado=NÃO, Alcançou=NÃO, Bônus=NÃO); T2(NÃO,NÃO,NÃO,NÃO); T3(NÃO,SIM,SIM,NÃO); T4(SIM,SIM,SIM,SIM). Qual dos seguintes casos de teste representa uma situação que pode acontecer na vida real, e está faltando na tabela de decisão acima?`, options: [`Condição 1 = SIM, Condição 2 = NÃO, Condição 3 = SIM, Ação = NÃO`, `Condição 1 = SIM, Condição 2 = SIM, Condição 3 = NÃO, Ação = SIM`, `Condição 1 = NÃO, Condição 2 = NÃO, Condição 3 = SIM, Ação = NÃO`, `Condição 1 = NÃO, Condição 2 = SIM, Condição 3 = NÃO, Ação = NÃO`], answerIndex: 3, explanation: `A tabela original não cobre a combinação onde o funcionário tem menos de 1 ano mas já possui objetivo acordado sem alcançá-lo — situação plausível e ausente, com ação 'não paga bônus'.` },
  { id: "c4-31", chapter: 4, prompt: `Uma aplicação de vídeo deve permitir a reprodução em: 640x480, 1280x720, 1600x1200, 1920x1080. Qual dos seguintes casos de teste é resultado da aplicação da técnica de particionamento de equivalência para testar este requisito?`, options: [`Verificar se a aplicação pode reproduzir um vídeo em uma tela de tamanho 1920x1080 (1 caso de teste)`, `Verificar se a aplicação pode reproduzir um vídeo em um display de tamanho 640x480 e 1920x1080 (2 casos de teste)`, `Verificar se a aplicação pode reproduzir um vídeo em cada um dos tamanhos de exibição na exigência (4 casos de teste)`, `Verificar se a aplicação pode reproduzir um vídeo em qualquer um dos tamanhos de tela na exigência (1 caso de teste)`], answerIndex: 2, explanation: `Como cada resolução é uma exigência distinta e específica (não uma faixa contínua de valores), cada uma forma sua própria partição válida, exigindo <b>4 casos de teste</b>.` },
  { id: "c4-32", chapter: 4, prompt: `Qual dos itens a seguir fornece a MELHOR descrição de testes exploratórios?`, options: [`Uma prática de teste na qual uma investigação aprofundada dos antecedentes do objeto de teste é utilizada para identificar potenciais pontos fracos que são examinados pelos casos de teste.`, `Uma abordagem aos testes em que os testadores projetam e executam dinamicamente testes baseados em seu conhecimento, exploração do item de teste e nos resultados dos testes anteriores.`, `Uma abordagem de projeto de teste na qual as atividades de teste são planejadas como sessões ininterruptas de análise e projeto de teste.`, `Testes baseados na experiência, conhecimento e intuição do testador.`], answerIndex: 1, explanation: `Essa é a definição formal de <b>teste exploratório</b> do glossário ISTQB.` },
  { id: "c4-33", chapter: 4, prompt: `Qual dos seguintes MELHOR combina as descrições com as diferentes categorias de técnicas de teste? (1) A cobertura é medida com base em uma estrutura selecionada do objeto de teste. (2) O processamento dentro do objeto de teste é verificado. (3) Os testes são baseados na probabilidade de defeitos e sua distribuição. (4) Os desvios das exigências são verificados. (5) As histórias de usuários são usadas como base de teste. Usando: Preto - técnicas caixa-preta; Branco - técnicas caixa-branca; Experiência - técnicas baseadas na experiência.`, options: [`Preto-4, 5; Branco - 1, 2; Experiência - 3`, `Preto - 3; Branco - 1, 2; Experiência - 4, 5`, `Preto - 4; Branco - 1, 2; Experiência - 3, 5`, `Preto - 1, 3, 5; Branco - 2; Experiência - 4`], answerIndex: 0, explanation: `Caixa-preta verifica desvios de requisitos e usa histórias de usuário (4,5); caixa-branca mede cobertura estrutural e processamento interno (1,2); baseada em experiência usa probabilidade/distribuição de defeitos (3).` },
  { id: "c4-34", chapter: 4, prompt: `Um aplicativo de fitness mede o número de passos diários. Feedback: até 1000 "Preguiçoso!"; acima de 1000 até 2000 "Molenga!"; acima de 2000 até 4000 "Chegando lá!"; acima de 4000 até 6000 "Nada mal!"; acima de 6000 "Muito bom!". Qual dos seguintes conjuntos de entradas de teste alcançaria a MELHOR cobertura de partição de equivalência?`, options: [`0, 1000, 2000, 3000, 4000`, `1000, 2001, 4000, 4001, 6000`, `123, 2345, 3456, 4567, 5678`, `666, 999, 2222, 5555, 6666`], answerIndex: 3, explanation: `Um valor de cada uma das 5 partições válidas (≤1000, 1001–2000, 2001–4000, 4001–6000, >6000) garante cobertura total de partição de equivalência.` },
  { id: "c4-35", chapter: 4, prompt: `Um gravador de radiação diário para plantas produz uma pontuação combinando horas de exposição ao sol (abaixo de 3h, 3 a 6h, acima de 6h) e intensidade média (muito baixa, baixa, média, alta). Casos de teste: T1(1,5h, Muito Baixa, 10); T2(7,0h, Média, 60); T3(0,5h, Muito Baixa, 10). Qual é o número mínimo de casos de teste adicionais necessários para garantir a cobertura total de TODAS as partições de equivalência de entrada válida?`, options: [`1`, `2`, `3`, `4`], answerIndex: 1, explanation: `As partições de horas (3) e intensidade (4) ainda não cobertas pelos casos T1-T3 exigem <b>2 casos de teste adicionais</b> para completar a cobertura de todas as partições válidas.` },
  { id: "c4-36", chapter: 4, prompt: `Um aplicativo doméstico inteligente mede a temperatura média semanal. Feedback: até 10ºC "Gelado"; 11ºC a 15ºC "Refrigerado"; 16ºC a 19ºC "Agradável"; 20ºC a 22ºC "Quente"; acima de 22ºC "Muito quente". Usando BVA (somente valores Mínimos e Máximos), qual dos seguintes conjuntos de entradas de teste fornece o mais alto nível de cobertura de limite?`, options: [`0ºC, 11ºC, 20ºC, 22ºC, 23ºC`, `9ºC, 15ºC, 19ºC, 23ºC, 100ºC`, `10ºC, 16ºC, 19ºC, 22ºC, 23ºC`, `14ºC, 15ºC, 18ºC, 19ºC, 19ºC, 21ºC, 22ºC`], answerIndex: 2, explanation: `O conjunto cobre os valores mínimo/máximo de cada faixa (10, 16, 19, 22 e 23), maximizando a cobertura de limites com o menor número de valores.` },
  { id: "c4-37", chapter: 4, prompt: `Testes de tabela de decisão em um sistema de multa por excesso de velocidade. Casos já gerados para R1 (Velocidade>50=T, Zona escolar=T, Multa=F, Recolhimento=T) e R4 (F,F,F,F). Casos adicionais: DT1(55,T), DT2(44,T), DT3(66,T), DT4(77,F). Quais dos dois casos de teste adicionais alcançariam cobertura total da tabela de decisão completa?`, options: [`DT1, DT2`, `DT2, DT3`, `DT2, DT4`, `DT3, DT4`], answerIndex: 2, explanation: `DT2 (44 km/h, zona escolar) e DT4 (77 km/h, fora de zona escolar) completam as combinações de regras ainda não cobertas pelos casos originais R1 e R4.` },
  { id: "c4-38", chapter: 4, prompt: `Qual das seguintes declarações MELHOR descreve como os casos de teste são derivados de um caso de uso?`, options: [`Os casos de teste são criados para exercitar comportamentos básicos, excepcionais e de erro definidos pelo sistema em teste, em colaboração com os atores.`, `Os casos de teste são derivados da identificação dos componentes incluídos no caso de uso e da criação de testes de integração.`, `Os casos de teste são gerados através da análise das interações dos atores com o sistema para garantir que as interfaces sejam fáceis de usar.`, `Os casos de teste são derivados para exercer cada um dos pontos de decisão nos fluxos do processo comercial, para atingir 100% de cobertura de decisão.`], answerIndex: 0, explanation: `Casos de teste baseados em <b>casos de uso</b> exercitam os fluxos básico, alternativo e de exceção definidos na interação entre atores e sistema.` },
  { id: "c4-39", chapter: 4, prompt: `Qual das seguintes descrições de cobertura de declarações é CORRETA?`, options: [`A cobertura de declaração é uma medida do número de linhas de código fonte exercidas por testes.`, `A cobertura de declarações é uma medida da proporção de declarações executáveis no código fonte exercida por testes.`, `A cobertura de declaração é uma medida da porcentagem de linhas de código fonte (sem comentários) exercida por testes.`, `A cobertura de declarações é uma medida do número de declarações executáveis no código fonte exercido por testes.`], answerIndex: 1, explanation: `A definição correta usa <b>proporção (percentual)</b> de instruções executáveis, não a contagem absoluta de linhas.` },
  { id: "c4-40", chapter: 4, prompt: `Qual das seguintes descrições de cobertura de decisão é CORRETA?`, options: [`A cobertura de decisão é uma medida da porcentagem de caminhos possíveis através do código fonte exercida por testes.`, `A cobertura de decisão é uma medida da porcentagem dos fluxos comerciais através do componente exercido por testes.`, `A cobertura de decisão é uma medida das declarações "se" no código que são exercidas tanto com os resultados verdadeiros como falsos.`, `A cobertura de decisão é uma medida da proporção de resultados de decisão no código fonte exercida por testes.`], answerIndex: 3, explanation: `Por definição, <b>cobertura de decisão</b> é a proporção de resultados de decisão (desfechos verdadeiro/falso) do código-fonte exercitados pelos testes.` },
  { id: "c4-41", chapter: 4, prompt: `Qual dos seguintes itens descreve MELHOR o conceito por trás da adivinhação de erros?`, options: [`A adivinhação de erros requer que você imagine que é o usuário do objeto de teste e adivinhe os erros que o usuário poderia cometer ao interagir com ele.`, `A adivinhação de erros envolve o uso de sua experiência pessoal de desenvolvimento e os erros que você cometeu como desenvolvedor.`, `A suposição de erros envolve o uso de seu conhecimento e experiência de defeitos encontrados no passado e erros típicos cometidos pelos desenvolvedores.`, `A adivinhação de erros exige que você duplique rapidamente a tarefa de desenvolvimento para identificar o tipo de erros que um desenvolvedor pode cometer.`], answerIndex: 2, explanation: `A <b>suposição de erro (error guessing)</b> usa o conhecimento e a experiência do testador sobre defeitos passados e erros típicos de desenvolvedores.` },
  { id: "c4-42", chapter: 4, prompt: `O que é teste baseado em checklist?`, options: [`Uma técnica de teste na qual os testes são derivados com base no conhecimento do testador sobre falhas do passado, ou conhecimento geral de falhas`, `Uma técnica de teste baseada em uma análise da especificação de um componente ou sistema`, `Uma técnica de teste baseada na experiência em que o testador experiente usa uma lista de itens a serem anotados, verificados ou lembrados, ou um conjunto de regras, ou critérios contra os quais um produto deve ser verificado`, `Uma abordagem aos testes onde os testadores projetam e executam testes dinamicamente baseados em seu conhecimento, exploração do item de teste e nos resultados dos testes anteriores`], answerIndex: 2, explanation: `O <b>teste baseado em checklist</b> usa uma lista pré-definida de itens ou critérios que o testador experiente verifica sistematicamente.` },

  // ---------------- Capítulo 5 ----------------
  { id: "c5-01", chapter: 5, prompt: "Critérios de entrada e de saída servem para:", options: ["Definir a linguagem", "Estabelecer condições para iniciar (entrada) e concluir (saída) uma atividade", "Substituir o plano de teste", "Medir cobertura de código"], answerIndex: 1, explanation: "<b>Entrada</b> = quando começar; <b>saída</b> = quando concluir (DoR/DoD no ágil)." },
  { id: "c5-02", chapter: 5, prompt: "A diferença entre risco de produto e risco de projeto é:", options: ["Produto: prazos; Projeto: qualidade", "Produto: qualidade do produto (defeitos/falhas); Projeto: gestão (prazos, recursos, pessoas)", "São sinônimos", "Ambos tratam só de custo"], answerIndex: 1, explanation: "<b>Produto</b>: falha/qualidade. <b>Projeto</b>: cronograma, recursos, fornecedores." },
  { id: "c5-03", chapter: 5, prompt: "O nível de um risco é determinado por:", options: ["Apenas a probabilidade", "A probabilidade combinada ao impacto", "Apenas o custo de correção", "O número de testadores"], answerIndex: 1, explanation: "Nível de risco = <b>probabilidade × impacto</b>." },
  { id: "c5-04", chapter: 5, prompt: "O teste baseado em risco usa a análise de risco para:", options: ["Eliminar documentação", "Priorizar e alocar o esforço de teste conforme os riscos", "Automatizar tudo", "Definir a linguagem"], answerIndex: 1, explanation: "Riscos guiam prioridade, profundidade e ordem — mais esforço onde o risco é maior." },
  { id: "c5-05", chapter: 5, prompt: "A pirâmide de testes sugere ter:", options: ["Mais testes de UI/E2E e poucos unitários", "Mais testes de baixo nível (unitários, rápidos/baratos) e menos de alto nível (UI/E2E)", "O mesmo número em todos os níveis", "Apenas testes manuais"], answerIndex: 1, explanation: "Base ampla de unitários; topo estreito de UI/E2E (lentos, caros, frágeis)." },
  { id: "c5-06", chapter: 5, prompt: "Qual item é essencial em um bom relatório de defeito?", options: ["Só o título", "Passos para reproduzir, resultado esperado x obtido, severidade/prioridade e status", "Só o nome do dev", "Só a data"], answerIndex: 1, explanation: "Inclui ID, descrição, <b>passos, esperado x real, severidade, prioridade e status</b>." },
  { id: "c5-07", chapter: 5, prompt: "Severidade e prioridade de um defeito diferem porque:", options: ["Severidade = urgência; prioridade = impacto técnico", "Severidade = impacto no sistema; prioridade = urgência da correção (negócio)", "São sempre iguais", "Nenhuma afeta o planejamento"], answerIndex: 1, explanation: "<b>Severidade</b>: impacto técnico. <b>Prioridade</b>: urgência (negócio). Podem divergir." },
  { id: "c5-08", chapter: 5, prompt: "Na estimativa por três pontos (PERT), a estimativa esperada é:", options: ["(otimista + pessimista) / 2", "(otimista + 4×mais provável + pessimista) / 6", "mais provável × 3", "(otimista × pessimista) / provável"], answerIndex: 1, explanation: "<b>E = (a + 4m + b) / 6</b> — reduz o peso dos extremos." },
  { id: "c5-09", chapter: 5, prompt: "A gerência de configuração, no teste, garante:", options: ["Correção automática de defeitos", "Integridade e rastreabilidade dos itens de teste e testware, com versionamento", "A execução dos testes", "A escrita dos requisitos"], answerIndex: 1, explanation: "Controla versões e mantém <b>rastreabilidade e integridade</b> do testware." },
  { id: "c5-10", chapter: 5, prompt: "O relatório de conclusão de teste (test summary) serve para:", options: ["Iniciar o projeto", "Resumir as atividades e resultados de teste ao final de uma fase/marco", "Substituir o plano de teste", "Registrar um único defeito"], answerIndex: 1, explanation: "Sumariza o que foi testado, resultados e desvios — apoia decisões de liberação." },
  { id: "c5-11", chapter: 5, prompt: "Planning poker é um exemplo de qual técnica de estimativa?", options: ["Baseada em razão", "Baseada na opinião de especialistas (wideband Delphi)", "Extrapolação", "Três pontos"], answerIndex: 1, explanation: "É uma variação de <b>wideband Delphi</b> — estimativa colaborativa por especialistas." },
  { id: "c5-12", chapter: 5, prompt: "O Quadrante Q1 de teste (Brian Marick) contém:", options: ["Testes exploratórios e de usabilidade", "Testes de componente e integração de componentes, automatizados e incluídos no CI", "Testes não funcionais e smoke tests", "Testes funcionais e histórias de usuário"], answerIndex: 1, explanation: "<b>Q1</b>: voltado para tecnologia, apoia a equipe — testes de componente e integração, automatizados no CI." },
  { id: "c5-13", chapter: 5, prompt: "O Quadrante Q3 de teste é caracterizado por:", options: ["Testes automatizados voltados para tecnologia", "Testes de negócio, exploratórios e de usabilidade, orientados ao usuário e geralmente manuais", "Smoke tests e testes de performance", "Testes de aceitação automatizados"], answerIndex: 1, explanation: "<b>Q3</b>: voltado para negócio, avalia o produto — exploratório, usabilidade, UAT — geralmente manuais." },
  { id: "c5-14", chapter: 5, prompt: "Na priorização de casos de teste por 'cobertura adicional', a ordem de execução é:", options: ["Primeiro os mais curtos", "O caso com maior cobertura primeiro; cada subsequente adiciona a maior cobertura incremental", "Aleatória", "Por ordem de criação"], answerIndex: 1, explanation: "<b>Cobertura adicional</b>: primeiro o caso com maior cobertura, depois o que mais adiciona cobertura incremental." },
  { id: "c5-15", chapter: 5, prompt: "A 'baseline' no gerenciamento de configuração significa:", options: ["Um defeito encontrado no teste", "Um item de configuração aprovado para teste, alterável apenas via processo formal", "O plano inicial de teste", "A primeira versão do código"], answerIndex: 1, explanation: "<b>Baseline</b>: item aprovado para teste; mudanças exigem controle formal. Permite reverter para reproduzir resultados." },
  { id: "c5-16", chapter: 5, prompt: "A análise de risco do produto pode influenciar os testes ao:", options: ["Eliminar a necessidade de critérios de saída", "Determinar escopo, níveis, técnicas, cobertura, esforço e priorização dos testes", "Substituir o plano de teste", "Definir apenas o prazo do projeto"], answerIndex: 1, explanation: "A análise de risco influencia <b>escopo, níveis/tipos propostos, técnicas, cobertura, esforço, ordem</b> e outras atividades." },
  { id: "c5-17", chapter: 5, prompt: "Qual é a diferença entre DoR (Definition of Ready) e DoD (Definition of Done) no ágil?", options: ["São a mesma coisa", "DoR = critérios de entrada (para iniciar); DoD = critérios de saída (para considerar concluído)", "DoD vem antes do DoR", "DoR é para o produto; DoD é para a iteração"], answerIndex: 1, explanation: "<b>DoR</b> (Definition of Ready): critérios de entrada para iniciar dev/teste. <b>DoD</b> (Definition of Done): critérios de saída para liberação." },
  { id: "c5-18", chapter: 5, prompt: "O relatório de PROGRESSO de teste difere do relatório de CONCLUSÃO principalmente porque:", options: ["Progressos são mais formais que os de conclusão", "Progresso é gerado regularmente durante o teste; conclusão sumariza ao final de uma fase/marco", "Apenas o de conclusão inclui métricas", "São idênticos em conteúdo"], answerIndex: 1, explanation: "<b>Progresso</b>: gerado regularmente durante execução. <b>Conclusão</b>: sumariza uma fase completa — inclui lições aprendidas." },
  { id: "c5-19", chapter: 5, prompt: "Na estimativa baseada em ÍNDICES (razão), se a proporção histórica dev:teste é 3:2 e o esforço de dev estimado é 600 hh, o esforço de teste estimado é:", options: ["300 hh", "400 hh", "200 hh", "900 hh"], answerIndex: 1, explanation: "Razão dev:teste = 3:2 → teste = (2/3) × 600 = <b>400 hh</b>." },
  { id: "c5-20", chapter: 5, prompt: `Qual das seguintes declarações MELHOR descreve como as tarefas são divididas entre o gerente de testes e o testador?`, options: [`O gerente de testes planeja as atividades de teste e escolhe os padrões a serem seguidos, enquanto o testador escolhe as ferramentas e estabelece as diretrizes de uso.`, `O gerente de testes planeja, coordena e controla as atividades de teste, enquanto o testador automatiza os testes`, `O gerente de testes planeja, monitora e controla as atividades de teste, enquanto o testador projeta os testes e decide sobre a liberação do objeto de teste`, `O gerente de testes planeja e organiza os testes e especifica os casos de teste, enquanto o testador executa os testes`], answerIndex: 1, explanation: `O <b>gerente de testes</b> planeja, coordena e controla; o <b>testador</b> executa tarefas técnicas como automação, projeto e execução de testes.` },
  { id: "c5-21", chapter: 5, prompt: `Qual das seguintes métricas seria a mais útil para monitorar durante a execução do teste?`, options: [`Porcentagem de casos de teste executados.`, `Número médio de testadores envolvidos na execução do teste.`, `Cobertura dos requisitos pelo código fonte.`, `Porcentagem de casos de teste já criados e revisados.`], answerIndex: 0, explanation: `Durante a <b>execução</b>, a métrica mais útil para monitorar o progresso é o percentual de casos de teste já executados.` },
  { id: "c5-22", chapter: 5, prompt: `Qual dos seguintes aspectos pode afetar e fazer parte do planejamento (inicial) do teste?`, options: [`Limitações orçamentárias`, `Diário de testes`, `Taxa de falha`, `Casos de uso`], answerIndex: 0, explanation: `Restrições de <b>orçamento</b> afetam diretamente o escopo e a estratégia definidos no planejamento inicial do teste.` },
  { id: "c5-23", chapter: 5, prompt: `Qual das listas a seguir contém apenas os critérios típicos de saída dos testes?`, options: [`Medidas de confiabilidade, cobertura do teste, cronograma e status sobre a correção de defeitos e riscos remanescentes`, `Medidas de confiabilidade, cobertura de teste, grau de independência do testador e completude do produto`, `Medidas de confiabilidade, cobertura de teste, custo do teste, disponibilidade do ambiente de teste, tempo de colocação no mercado e completude do produto`, `Tempo para comercialização, defeitos restantes, qualificação do testador, disponibilidade de casos de uso testável, cobertura de teste e custo do teste`], answerIndex: 0, explanation: `Critérios de saída típicos incluem <b>confiabilidade, cobertura, cronograma e defeitos/riscos remanescentes</b>.` },
  { id: "c5-24", chapter: 5, prompt: `Qual dos itens a seguir NÃO está incluído em um relatório resumido de teste?`, options: [`Definição de critérios de aprovação/reprovação e objetivos dos testes`, `Desvios da abordagem de teste`, `Medições do progresso real em relação aos critérios de saída`, `Avaliação da qualidade do objeto de teste`], answerIndex: 0, explanation: `Critérios de aprovação e objetivos de teste são definidos no <b>plano de teste</b>, não no relatório resumo, que reporta resultados observados.` },
  { id: "c5-25", chapter: 5, prompt: `O projeto desenvolve um termostato de aquecimento "inteligente" com algoritmos modelados em Matlab/Simulink executados em servidor conectado à Internet. O gerente de teste definiu: 1. O teste de aceite para todo o sistema é executado como um teste baseado na experiência. 2. Os algoritmos de controle no servidor são verificados em relação ao padrão do regulamento de economia de energia. 3. O teste funcional do termostato é executado como um teste baseado em risco. 4. Os testes de segurança de dados/comunicação são executados com especialistas externos. Que quatro tipos comuns de estratégias/abordagens de teste o gerente de testes implementou?`, options: [`Metódico, analítico, reativo e avesso à regressão`, `Analítico, conforme às normas, consultivo e reativo`, `Baseada em modelos, metódica, analítica e consultiva`, `Regressão-aversão, consultiva, reativa e metódica`], answerIndex: 1, explanation: `Teste de aceitação baseado em experiência = <b>reativo</b>; verificação contra normas = <b>conforme às normas</b>; teste baseado em risco = <b>analítico</b>; testes com especialistas externos = <b>consultivo</b>.` },
  { id: "c5-26", chapter: 5, prompt: `Qual das seguintes é uma característica de uma abordagem baseada em métricas para a estimativa de teste?`, options: [`Orçamento que foi utilizado por um projeto de teste anterior semelhante.`, `Experiência geral coletada em entrevistas com gerentes de testes.`, `Estimativa de esforço para automação de testes acordada na equipe de teste.`, `Mediana dos cálculos coletados de especialistas empresariais.`], answerIndex: 0, explanation: `A abordagem <b>baseada em métricas</b> usa dados históricos, como o orçamento de projetos anteriores semelhantes.` },
  { id: "c5-27", chapter: 5, prompt: `Você está testando uma máquina de café que prepara diferentes tipos com base em tamanho, açúcar, leite e xarope. Você escreve um relatório de defeito com: Título (Baixa temperatura do café); Resumo (leite selecionado causa demora e temperatura abaixo de 40°C); Resultado esperado (75°C); Grau de risco (Médio); Prioridade (Normal). Que informação valiosa foi omitida no relatório de defeitos acima?`, options: [`Os resultados reais dos testes`, `Identificação da versão testada do software`, `Status do defeito`, `Ideias para melhorar o caso teste`], answerIndex: 1, explanation: `Um bom relatório de defeito deve identificar a <b>versão do software testada</b>, informação ausente no relato apresentado.` },
  { id: "c5-28", chapter: 5, prompt: `Qual das seguintes tarefas é MUITO MAIS EFICIENTE quando executada pelo gerente de testes?`, options: [`Escrever relatórios resumidos de testes com base nas informações coletadas durante os testes.`, `Revisar testes desenvolvidos por outros.`, `Preparar e adquirir dados de teste.`, `Analisar, revisar e avaliar os requisitos, especificações e modelos de testabilidade.`], answerIndex: 0, explanation: `Consolidar informações em <b>relatórios de resumo de teste</b> é uma tarefa tipicamente do gerente de testes, com visão geral do projeto.` },
  { id: "c5-29", chapter: 5, prompt: `Dados os seguintes exemplos: (1) Orçamento original de $30.000 mais contingência de $7.000 foi gasto. (2) 96% dos testes planejados foram executados e os restantes estão fora do escopo. (3) O ambiente de teste de desempenho foi projetado, montado e verificado. (4) Status atual: nenhum defeito crítico pendente e dois de alta prioridade. (5) As especificações de projeto do piloto automático foram revisadas e retrabalhadas. (6) O componente de cálculo da taxa de imposto passou nos testes unitários. Qual dos seguintes os classifica MELHOR como critérios de entrada e saída?`, options: [`Critérios de entrada - 5, 6; Critérios de saída - 1, 2, 3, 4.`, `Critérios de entrada - 2, 3, 6; Critérios de saída - 1, 4, 5.`, `Critérios de entrada - 1, 3; Critérios de saída - 2, 4, 5, 6.`, `Critérios de entrada - 3, 5, 6; Critérios de saída - 1, 2, 4.`], answerIndex: 3, explanation: `Ambiente pronto, especificações revisadas e testes unitários aprovados (3,5,6) são pré-condições (entrada); orçamento gasto, % executado e status de defeitos (1,2,4) são condições de conclusão (saída).` },
  { id: "c5-30", chapter: 5, prompt: `Prioridades e dependências: TC1(Alta, dep. técnica TC4); TC2(Baixa); TC3(Alta, dep. lógica TC4); TC4(Média); TC5(Baixa, dep. lógica TC2); TC6(Média, dep. técnica TC5). Qual dos seguintes cronogramas de execução de testes CONSIDERA MELHOR as prioridades e dependências técnicas e lógicas?`, options: [`TC1 - TC3 - TC4 - TC6 - TC2 - TC5`, `TC4 - TC3 - TC1 - TC2 - TC5 - TC6`, `TC4 - TC1 - TC3 - TC5 - TC6 - TC2`, `TC4 - TC2 - TC5 - TC1 - TC3 - TC6`], answerIndex: 1, explanation: `TC4 deve rodar antes de TC1 (dependência técnica) e TC3 (dependência lógica); TC2 antes de TC5 (dependência lógica); TC5 antes de TC6 (dependência técnica) — essa ordem respeita todas as dependências e prioridades.` },
  { id: "c5-31", chapter: 5, prompt: `Qual das seguintes afirmações sobre os métodos de estimativa de teste é CORRETA?`, options: [`Com a abordagem baseada em métricas, a estimativa é baseada em medidas de teste do projeto e só está disponível após o início dos testes.`, `Com a abordagem baseada em especialistas, um grupo de usuários experientes identificados pelo cliente recomenda o orçamento de teste necessário.`, `Com a abordagem baseada em especialistas, os gerentes de testes responsáveis pelas diferentes atividades de teste preveem o esforço de teste esperado.`, `Com a abordagem baseada em métricas, uma média dos custos de teste registrados de vários projetos passados é usada como orçamento de teste.`], answerIndex: 2, explanation: `Na abordagem <b>baseada em especialistas</b>, os responsáveis pelas atividades estimam o esforço com base em sua experiência.` },
  { id: "c5-32", chapter: 5, prompt: `Qual dos seguintes define MELHOR o nível de risco?`, options: [`O nível de risco é calculado somando as probabilidades de todas as situações problemáticas e os danos financeiros que delas resultam.`, `O nível de risco é estimado pela multiplicação da probabilidade de uma ameaça ao sistema pela chance de que a ameaça ocorra e resulte em dano financeiro.`, `O nível de risco é determinado por uma combinação da probabilidade de um evento indesejável e o impacto esperado desse evento.`, `O nível de risco é a soma de todos os perigos potenciais de um sistema multiplicada pela soma de todas as perdas potenciais desse sistema.`], answerIndex: 2, explanation: `Nível de risco = <b>probabilidade × impacto</b> de um evento indesejado.` },
  { id: "c5-33", chapter: 5, prompt: `Qual dos seguintes é o mais provável de ser um exemplo de risco de PRODUTO?`, options: [`As características de segurança esperadas podem não ser suportadas pela arquitetura do sistema.`, `Os desenvolvedores podem não ter tempo para corrigir todos os defeitos encontrados pela equipe de teste.`, `Os casos de teste podem não oferecer cobertura total dos requisitos especificados.`, `O ambiente de teste de desempenho pode não estar pronto antes que o sistema esteja pronto para entrega.`], answerIndex: 0, explanation: `Um <b>risco de produto</b> afeta a qualidade do sistema em si, como falhas potenciais na arquitetura de segurança; as demais opções são riscos de projeto.` },
  { id: "c5-34", chapter: 5, prompt: `Qual dos seguintes é o MENOS provável de ser um exemplo de análise de risco do produto INFLUENCIANDO CORRETAMENTE os testes?`, options: [`O impacto potencial das falhas de segurança foi identificado como particularmente alto, portanto os testes de segurança foram priorizados.`, `Os testes constataram que a qualidade do módulo de rede é superior ao esperado, portanto não serão realizados testes adicionais nessa área.`, `Os usuários tiveram problemas com a interface do sistema anterior, de modo que testes de usabilidade adicionais estão planejados para o substituto.`, `O tempo necessário para carregar as páginas web é crucial para o sucesso do novo site, por isso foi empregado um especialista em testes de desempenho.`], answerIndex: 1, explanation: `Resultados de teste indicando boa qualidade não devem, por si só, eliminar testes futuros de uma área — isso não representa a <b>análise de risco de produto</b> influenciando corretamente o planejamento.` },
  { id: "c5-35", chapter: 5, prompt: `Você está testando um sistema de reserva de trens e notou que o sistema ocasionalmente relata que não há trens disponíveis quando deveria haver. Você já forneceu resumo do defeito e versão do sistema testado. Informações adicionais possíveis: (1) Grau de impacto (gravidade); (2) Identificação do item de teste; (3) Detalhes do ambiente de teste; (4) Urgência/prioridade; (5) Resultados reais; (6) Referência à especificação do caso de teste. Qual destas informações é a mais útil para incluir no relatório de defeitos?`, options: [`1, 2, 6`, `1, 4, 5, 6`, `2, 3, 4, 5`, `3, 5, 6`], answerIndex: 3, explanation: `Detalhes do ambiente de teste, resultados reais e referência à especificação do caso de teste (3,5,6) são as informações mais úteis para complementar o relatório de defeito já compartilhado.` },

  // ---------------- Capítulo 6 ----------------
  { id: "c6-01", chapter: 6, prompt: "Qual é um risco comum da automação de testes?", options: ["Reduzir totalmente o esforço humano", "Expectativas irreais, subestimar a manutenção dos scripts e excesso de confiança na ferramenta", "Aumentar a repetibilidade", "Fornecer métricas objetivas"], answerIndex: 1, explanation: "Riscos: expectativas irreais, custo de <b>manutenção</b>, dependência do fornecedor." },
  { id: "c6-02", chapter: 6, prompt: "Um benefício típico de ferramentas de teste é:", options: ["Substituir a análise humana", "Reduzir trabalho repetitivo e aumentar consistência, repetibilidade e acesso a informações objetivas", "Garantir software sem defeitos", "Eliminar o planejamento"], answerIndex: 1, explanation: "Reduz repetição, aumenta consistência/repetibilidade e dá <b>medições objetivas</b>." },
  { id: "c6-03", chapter: 6, prompt: "Ao introduzir uma ferramenta de teste na organização, uma boa prática é:", options: ["Implantar para todos de uma vez", "Começar com um projeto-piloto para avaliar o ajuste antes de expandir", "Escolher sem avaliar necessidades", "Eliminar treinamento"], answerIndex: 1, explanation: "Um <b>projeto-piloto</b> avalia o encaixe com o contexto antes da adoção ampla." },
  { id: "c6-04", chapter: 6, prompt: "Ferramentas de execução de teste são mais valiosas para:", options: ["Substituir o design de teste", "Automatizar reteste e regressão repetitivos", "Escrever requisitos", "Gerenciar riscos de projeto"], answerIndex: 1, explanation: "Brilham em <b>regressão/reteste</b> — tarefas repetitivas e frequentes." },
  { id: "c6-05", chapter: 6, prompt: "Qual categoria de ferramenta de teste dá suporte a testes que são 'difíceis ou impossíveis de serem realizados manualmente'?", options: ["Ferramentas de colaboração", "Ferramentas de teste não funcional (performance, segurança)", "Ferramentas de gerenciamento", "Ferramentas de projeto e implementação"], answerIndex: 1, explanation: "Ferramentas de <b>teste não funcional</b> (carga, stress, segurança) executam cenários inviáveis manualmente." },
  { id: "c6-06", chapter: 6, prompt: "A dependência do fornecedor é um risco da automação porque:", options: ["O fornecedor melhora a ferramenta continuamente", "O fornecedor pode fechar, aposentar a ferramenta, vendê-la ou fornecer suporte deficiente", "Ferramentas de terceiros são sempre mais baratas", "Garante suporte 24h"], answerIndex: 1, explanation: "<b>Dependência do fornecedor</b>: risco de fechamento, aposentadoria, venda ou suporte ruim para a ferramenta." },
  { id: "c6-07", chapter: 6, prompt: "Ferramentas de DevOps no contexto de teste servem para:", options: ["Substituir a análise estática", "Suportar o pipeline de entrega CI/CD, rastreamento de fluxo e builds automatizadas", "Gerenciar apenas defeitos", "Criar dados de teste manualmente"], answerIndex: 1, explanation: "Ferramentas de <b>DevOps</b> suportam o pipeline CI/CD, rastreamento de fluxo e automação de builds." },
  { id: "c6-08", chapter: 6, prompt: `Qual dos seguintes é o MAIS provável que seja um benefício das ferramentas de execução de testes?`, options: [`É fácil criar testes de regressão.`, `É fácil manter o controle de versão dos ativos de teste.`, `É fácil projetar testes para testes de segurança.`, `É fácil executar testes de regressão.`], answerIndex: 3, explanation: `Ferramentas de <b>execução de testes</b> automatizam principalmente a repetição de testes de regressão.` },
  { id: "c6-09", chapter: 6, prompt: `Qual das seguintes ferramentas de teste é mais adequada para desenvolvedores do que para testadores?`, options: [`Ferramentas de gerenciamento de requisitos.`, `Ferramentas de gerenciamento da configuração.`, `Ferramentas de gerenciamento de defeitos.`, `Ferramentas de teste de desempenho.`], answerIndex: 2, explanation: `Ferramentas de <b>gerenciamento de defeitos</b> tendem a ser mais utilizadas no dia a dia dos desenvolvedores para acompanhar a correção de defeitos do que pelos testadores.` },
  { id: "c6-10", chapter: 6, prompt: `Dadas as seguintes atividades de teste e ferramentas de teste: (1) Medição de desempenho e análise dinâmica; (2) Execução de testes e registro; (3) Gerenciamento de testes e defeitos; (4) Projeto do teste. (a) Ferramentas de cobertura de requisitos; (b) Ferramentas de análise dinâmica; (c) Ferramentas de preparação de dados de teste; (d) Ferramentas de gerenciamento de defeitos. Qual dos seguintes MELHOR corresponde às atividades e ferramentas?`, options: [`1-B, 2-C, 3-D, 4-A`, `1-B, 2-D, 3-C, 4-A`, `1-B, 2-A, 3-D, 4-C`, `1-D, 2-B, 3-C, 4-A`], answerIndex: 2, explanation: `Medição de desempenho/análise dinâmica usa ferramentas de análise dinâmica (B); execução e registro usa ferramentas de cobertura (A); gerenciamento de testes/defeitos usa ferramentas de gerenciamento de defeitos (D); projeto do teste usa ferramentas de preparação de dados (C).` },
  { id: "c6-11", chapter: 6, prompt: `Qual dos seguintes é o mais provável de ser usado como motivo para usar um projeto piloto para introduzir uma ferramenta em uma organização?`, options: [`A necessidade de avaliar como a ferramenta se ajusta aos processos e práticas existentes e determinar o que precisaria mudar.`, `A necessidade de avaliar as habilidades de automação de testes e as necessidades de treinamento, mentoria e coaching dos testadores que irão utilizar a ferramenta.`, `A necessidade de avaliar se a ferramenta fornece a funcionalidade necessária e não duplica as ferramentas de teste existentes.`, `A necessidade de avaliar o fornecedor de ferramentas em termos de treinamento e outros tipos de apoio que eles fornecem.`], answerIndex: 0, explanation: `Um <b>projeto-piloto</b> avalia principalmente como a ferramenta se encaixa nos processos e práticas já existentes, revelando o que precisa mudar antes da adoção ampla.` },
];
